+}
+
+/// E2E test: Query results are machine-parseable.
+#[test]
+fn e2e_query_results_parseable() {
+    let columns = vec!["a".to_string(), "b".to_string()];
+    let rows = vec![vec!["1".to_string(), "2".to_string()]];
+
+    let results = QueryResults::new(columns, rows);
