+
+/// E2E test: Query results JSON serialization.
+#[test]
+fn e2e_query_results_json() {
+    let columns = vec!["id".to_string(), "name".to_string()];
+    let rows = vec![vec!["1".to_string(), "Test".to_string()]];
+
+    let results = QueryResults::new(columns, rows);
