+    assert!(json_str.contains("Test"));
+}
+
+// ============================================================================
+// Format Tests
+// ============================================================================
+
+/// E2E test: Pipe-delimited format.
+#[test]
+fn e2e_pipe_delimited_format() {
+    let columns = vec!["id".to_string(), "name".to_string()];
